<div class="d-flex justify-content-between mb-2"><h1 class="h5">Planes</h1><a href="/admin/planes/crear" class="btn btn-primary btn-sm">Nuevo plan</a></div><div class="table-responsive"><table class="table table-sm"><thead><tr><th>Nombre</th><th>Slug</th><th>Mensual</th><th>Visible</th><th>Estado</th><th class="text-end">Acciones</th></tr></thead><tbody><?php foreach($planes as $plan): ?><tr><td><?= e($plan['nombre']) ?></td><td><?= e($plan['slug']) ?></td><td>$<?= number_format((float)$plan['precio_mensual'],2) ?></td><td><?= $plan['visible'] ? 'Sí' : 'No' ?></td><td><span class="badge text-bg-light"><?= e($plan['estado']) ?></span></td><td class="text-end"><div class="dropdown"><button class="btn btn-light btn-sm dropdown-toggle" data-bs-toggle="dropdown">Acciones</button><ul class="dropdown-menu dropdown-menu-end"><li><a class="dropdown-item" href="/admin/planes/editar/<?= $plan['id'] ?>">Editar</a></li><li><a class="dropdown-item" href="/admin/plan-funcionalidades/<?= $plan['id'] ?>">Funcionalidades</a></li></ul></div></td></tr><?php endforeach; ?></tbody></table></div>
